from flask import Flask, request, jsonify
from web3 import Web3
import os

app = Flask(__name__)

# Initialize Web3
infura_url = os.getenv('INFURA_URL')
web3 = Web3(Web3.HTTPProvider(infura_url))

@app.route('/verify-signature', methods=['POST'])
def verify_signature():
    try:
        data = request.json
        message = data.get('message')
        signature = data.get('signature')
        expected_address = data.get('address')

        if not message or not signature or not expected_address:
            return jsonify({'error': 'Invalid input'}), 400

        # Hash the message
        message_hash = web3.keccak(text=message)

        # Recover the address from the signature
        recovered_address = web3.eth.account.recoverHash(message_hash, signature=signature)

        # Compare the recovered address with the expected address
        if web3.toChecksumAddress(recovered_address) == web3.toChecksumAddress(expected_address):
            return jsonify({'success': True, 'address': recovered_address}), 200
        else:
            return jsonify({'success': False, 'error': 'Address mismatch'}), 401

    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)